mapper.select:
SELECT id, student_id, book_id, book_name, daily_count, total_words, total_days, status, superseded_at, created_at
FROM recite_plan
WHERE id = #{id}
  AND student_id = #{studentId}
LIMIT 1

mapper.update:
UPDATE recite_plan
SET status = 'SUPERSEDED',
    superseded_at = #{supersededAt}
WHERE student_id = #{studentId}
  AND status = 'ACTIVE'
